    /*
     * Functional expectation: for normal Type 1 (RLE) streams, the checksum byte
     * is computed over the COMPRESSED payload (not the decompressed output).
     * Keep security behavior by verifying decompressed checksum above, but also
     * accept payload checksum for compatibility.
     */
    if (type == 1) {
        uint8_t payload_ck = (payload_len > 0) ? checksum8_sum(compressed_data + payload_off, payload_len) : 0;
        if (payload_ck != provided_ck) {
            if (allocated_here) {
                safe_free(&ctx->temp_buffer);
                ctx->buffer_size = 0;
            }
            return -1;
        }
    }

    /* Success: ctx->temp_buffer remains owned by caller to free later. */
    return 0;
}
